async function runWithExtendedThinking(userMessage, thinkingBudget = 8000) {
  const messages = [{ role: "user", content: userMessage }];

  while (true) {
    const response = await anthropic.messages.create({
      model: "claude-3-7-sonnet-20250219",
      max_tokens: 16000, // Must be > thinking budget
      thinking: {
        type: "enabled",
        budget_tokens: thinkingBudget, // Min: 1024
      },
      tools: claudeTools,
      messages,
    });

    // Extract blocks
    const thinkingBlocks = response.content.filter(b => b.type === "thinking");
    const toolUseBlocks = response.content.filter(b => b.type === "tool_use");
    const textBlocks = response.content.filter(b => b.type === "text");

    // Show thinking (optional)
    if (process.env.SHOW_THINKING) {
      for (const tb of thinkingBlocks) {
        console.log("[thinking]", tb.thinking.slice(0, 500) + "...");
      }
    }

    // Include ALL blocks (including thinking) in continuation
    messages.push({ role: "assistant", content: response.content });

    if (response.stop_reason === "tool_use") {
      // Call tools
      const toolResults = await Promise.all(
        toolUseBlocks.map(async (toolUse) => {
          const result = await mcpClient.callTool({
            name: toolUse.name,
            arguments: toolUse.input,
          });
          return { 
            type: "tool_result", 
            tool_use_id: toolUse.id, 
            content: result.content 
          };
        })
      );
      messages.push({ role: "user", content: toolResults });
    } else {
      return textBlocks.map(b => b.text).join("");
    }
  }
}

// ✅ CORRECT: Include ALL blocks including thinking
